mapper.select:
select hr.id, hr.user_id as userId, hr.health_item_id as healthItemId, hr.value, hr.create_time as createTime, u.username, u.avatar, hi.name as healthItemName, hi.unit as healthItemUnit, hi.normal_value as normalValue from `health_record` hr left join `user` u on u.id = hr.user_id left join `health_item` hi on hi.id = hr.health_item_id
and hr.health_item_id = #{healthItemId} and hr.user_id = #{userId}
order by id desc

select hr.value, hr.create_time as createTime
from `health_record` hr

    and hr.health_item_id = #{healthItemId}
    and hr.user_id = #{userId}

        and hr.create_time between #{startTime} and #{endTime}


order by hr.create_time

SELECT hi.name AS healthItemName, hr.value AS healthRecordValue, hi.normal_value AS normalValue, hr.create_time AS createTime FROM `health_record` hr INNER JOIN `health_item` hi ON hi.id = hr.health_item_id
AND hr.user_id = #{userId}
AND hr.health_item_id = #{healthItemId}
AND hr.create_time >= #{startTime} AND hr.create_time < DATE_ADD(#{endTime}, INTERVAL 1 DAY)
ORDER BY hr.create_time ASC
